module reg16_sync (
    input clk,
    input load,
    input clr,
    input [15:0] d,
    output [15:0] q
);

    reg [15:0] r_reg;

    always @(posedge clk) begin
        if (clr)
            r_reg <= 16'b0;
        else if (load)
            r_reg <= d;
    end

    assign q = r_reg;

endmodule
